using UnityEngine;
using UnityEngine.UI;
using TowerDefense.Core;

namespace TowerDefense.UI
{
    public class GameUI : MonoBehaviour
    {
        [Header("Top Bar")]
        [SerializeField] private Image _goldIcon;
        [SerializeField] private Text _goldText;
        [SerializeField] private Image _lifeIcon;
        [SerializeField] private Text _lifeText;
        [SerializeField] private Image _waveIcon;
        [SerializeField] private Text _waveText;

        [Header("Wave Info")]
        [SerializeField] private GameObject _waveInfoPanel;
        [SerializeField] private Text _waveTimerText;
        [SerializeField] private Text _enemyCountText;
        [SerializeField] private Button _startWaveButton;

        [Header("Tower Selection")]
        [SerializeField] private GameObject _towerSelectPanel;
        [SerializeField] private Transform _towerButtonContainer;
        [SerializeField] private GameObject _towerButtonPrefab;

        [Header("Tower Info")]
        [SerializeField] private GameObject _towerInfoPanel;
        [SerializeField] private Text _towerNameText;
        [SerializeField] private Text _towerLevelText;
        [SerializeField] private Text _towerDamageText;
        [SerializeField] private Button _upgradeButton;
        [SerializeField] private Text _upgradeCostText;
        [SerializeField] private Button _sellButton;
        [SerializeField] private Text _sellValueText;

        [Header("Game Controls")]
        [SerializeField] private Button _pauseButton;
        [SerializeField] private Button _speedButton;
        [SerializeField] private GameObject _pauseMenu;
        [SerializeField] private GameObject _gameOverPanel;
        [SerializeField] private GameObject _victoryPanel;

        [Header("Settings")]
        [SerializeField] private Slider _volumeSlider;
        [SerializeField] private Toggle _soundToggle;

        private Tower.TowerSlot _selectedSlot;
        private Tower.Tower _selectedTower;

        private void Start()
        {
            InitializeUI();
            SubscribeToEvents();
        }

        private void InitializeUI()
        {
            if (_pauseMenu != null) _pauseMenu.SetActive(false);
            if (_gameOverPanel != null) _gameOverPanel.SetActive(false);
            if (_victoryPanel != null) _victoryPanel.SetActive(false);
            if (_towerInfoPanel != null) _towerInfoPanel.SetActive(false);
            if (_towerSelectPanel != null) _towerSelectPanel.SetActive(false);

            UpdateGoldDisplay(GameManager.Instance.CurrentGold);
            UpdateLifeDisplay(GameManager.Instance.CurrentLife);
            UpdateWaveDisplay(GameManager.Instance.CurrentWave);

            if (_startWaveButton != null)
            {
                _startWaveButton.onClick.AddListener(OnStartWaveClicked);
            }
            if (_pauseButton != null)
            {
                _pauseButton.onClick.AddListener(OnPauseClicked);
            }
            if (_speedButton != null)
            {
                _speedButton.onClick.AddListener(OnSpeedClicked);
            }
            if (_upgradeButton != null)
            {
                _upgradeButton.onClick.AddListener(OnUpgradeClicked);
            }
            if (_sellButton != null)
            {
                _sellButton.onClick.AddListener(OnSellClicked);
            }
        }

        private void SubscribeToEvents()
        {
            GameManager.Instance.OnGoldChanged += UpdateGoldDisplay;
            GameManager.Instance.OnLifeChanged += UpdateLifeDisplay;
            GameManager.Instance.OnWaveChanged += UpdateWaveDisplay;
            GameManager.Instance.OnStateChanged += OnGameStateChanged;

            EventBus.Subscribe<GoldChangedEvent>(OnGoldChanged);
            EventBus.Subscribe<LifeChangedEvent>(OnLifeChanged);
        }

        private void OnDestroy()
        {
            if (GameManager.Instance != null)
            {
                GameManager.Instance.OnGoldChanged -= UpdateGoldDisplay;
                GameManager.Instance.OnLifeChanged -= UpdateLifeDisplay;
                GameManager.Instance.OnWaveChanged -= UpdateWaveDisplay;
                GameManager.Instance.OnStateChanged -= OnGameStateChanged;
            }

            EventBus.Unsubscribe<GoldChangedEvent>(OnGoldChanged);
            EventBus.Unsubscribe<LifeChangedEvent>(OnLifeChanged);
        }

        #region Display Updates

        private void UpdateGoldDisplay(int gold)
        {
            if (_goldText != null)
            {
                _goldText.text = gold.ToString();
            }

            if (_goldIcon != null)
            {
                _goldIcon.enabled = true;
            }
        }

        private void UpdateLifeDisplay(int life)
        {
            if (_lifeText != null)
            {
                _lifeText.text = life.ToString();
            }

            if (_lifeIcon != null)
            {
                _lifeIcon.enabled = true;
            }
        }

        private void UpdateWaveDisplay(int wave)
        {
            if (_waveText != null)
            {
                _waveText.text = $"{wave}/{GameManager.Instance.TotalWaves}";
            }

            if (_waveIcon != null)
            {
                _waveIcon.enabled = true;
            }
        }

        private void OnGoldChanged(GoldChangedEvent e)
        {
            UpdateGoldDisplay(e.CurrentGold);
        }

        private void OnLifeChanged(LifeChangedEvent e)
        {
            UpdateLifeDisplay(e.CurrentLife);
        }

        #endregion

        #region Tower Selection

        public void ShowTowerSelectPanel(Tower.TowerSlot slot)
        {
            _selectedSlot = slot;
            if (_towerSelectPanel != null)
            {
                _towerSelectPanel.SetActive(true);
            }
        }

        public void HideTowerSelectPanel()
        {
            _selectedSlot = null;
            if (_towerSelectPanel != null)
            {
                _towerSelectPanel.SetActive(false);
            }
        }

        public void SelectTower(Data.TowerData towerData)
        {
            if (_selectedSlot != null)
            {
                _selectedSlot.PlaceTower(towerData);
                HideTowerSelectPanel();
            }
        }

        #endregion

        #region Tower Info

        public void ShowTowerInfo(Tower.Tower tower)
        {
            _selectedTower = tower;

            if (_towerInfoPanel != null)
            {
                _towerInfoPanel.SetActive(true);
            }

            UpdateTowerInfo();
        }

        public void HideTowerInfo()
        {
            _selectedTower = null;
            if (_towerInfoPanel != null)
            {
                _towerInfoPanel.SetActive(false);
            }
        }

        private void UpdateTowerInfo()
        {
            if (_selectedTower == null) return;

            if (_towerNameText != null)
            {
                _towerNameText.text = _selectedTower.Data.towerName;
            }
            if (_towerLevelText != null)
            {
                _towerLevelText.text = $"Level: {_selectedTower.CurrentLevel}";
            }
            if (_towerDamageText != null)
            {
                _towerDamageText.text = $"Damage: {_selectedTower.CurrentStats.damage}";
            }
            if (_upgradeCostText != null)
            {
                int cost = _selectedTower.GetUpgradeCost();
                _upgradeCostText.text = cost > 0 ? cost.ToString() : "MAX";
            }
            if (_sellValueText != null)
            {
                _sellValueText.text = _selectedTower.GetSellValue().ToString();
            }
            if (_upgradeButton != null)
            {
                _upgradeButton.interactable = !_selectedTower.IsMaxLevel;
            }
        }

        #endregion

        #region Button Handlers

        private void OnStartWaveClicked()
        {
            Wave.WaveManager waveManager = FindObjectOfType<Wave.WaveManager>();
            if (waveManager != null)
            {
                waveManager.ForceStartWave();
            }

            if (_startWaveButton != null)
            {
                _startWaveButton.gameObject.SetActive(false);
            }
        }

        private void OnPauseClicked()
        {
            GameManager.Instance.TogglePause();

            if (_pauseMenu != null)
            {
                _pauseMenu.SetActive(GameManager.Instance.CurrentState == GameState.Paused);
            }
        }

        private void OnSpeedClicked()
        {
            float currentSpeed = GameManager.Instance.GameSpeed;
            float newSpeed = currentSpeed >= 3f ? 1f : currentSpeed + 1f;

            if (_speedButton != null)
            {
                Text textComponent = _speedButton.GetComponentInChildren<Text>();
                if (textComponent != null)
                {
                    textComponent.text = $"{newSpeed}x";
                }
            }
        }

        private void OnUpgradeClicked()
        {
            if (_selectedTower != null)
            {
                _selectedTower.Upgrade();
                UpdateTowerInfo();
            }
        }

        private void OnSellClicked()
        {
            if (_selectedTower != null)
            {
                _selectedTower.Sell();
                HideTowerInfo();
            }
        }

        #endregion

        #region Game State

        private void OnGameStateChanged(GameState state)
        {
            switch (state)
            {
                case GameState.Paused:
                    ShowPauseMenu();
                    break;
                case GameState.Playing:
                    HidePauseMenu();
                    break;
                case GameState.GameOver:
                    ShowGameOver();
                    break;
                case GameState.Victory:
                    ShowVictory();
                    break;
            }
        }

        private void ShowPauseMenu()
        {
            if (_pauseMenu != null)
            {
                _pauseMenu.SetActive(true);
            }
        }

        private void HidePauseMenu()
        {
            if (_pauseMenu != null)
            {
                _pauseMenu.SetActive(false);
            }
        }

        private void ShowGameOver()
        {
            if (_gameOverPanel != null)
            {
                _gameOverPanel.SetActive(true);
            }
        }

        private void ShowVictory()
        {
            if (_victoryPanel != null)
            {
                _victoryPanel.SetActive(true);
            }
        }

        #endregion

        #region Wave Timer

        public void UpdateWaveTimer(float time)
        {
            if (_waveTimerText != null)
            {
                if (time > 0)
                {
                    _waveTimerText.text = $"Next Wave: {Mathf.CeilToInt(time)}s";
                }
                else
                {
                    _waveTimerText.text = "Wave In Progress";
                }
            }
        }

        public void UpdateEnemyCount(int count)
        {
            if (_enemyCountText != null)
            {
                _enemyCountText.text = $"Enemies: {count}";
            }
        }

        #endregion
    }
}

using UnityEngine;
using UnityEngine.UI;
using UnityEngine.SceneManagement;
using TowerDefense.Core;
using TowerDefense.Data;

namespace TowerDefense.UI
{
    public class MainMenuUI : MonoBehaviour
    {
        [Header("Panels")]
        [SerializeField] private GameObject _mainPanel;
        [SerializeField] private GameObject _levelSelectPanel;
        [SerializeField] private GameObject _settingsPanel;

        [Header("Level Selection")]
        [SerializeField] private Transform _levelButtonContainer;
        [SerializeField] private GameObject _levelButtonPrefab;

        [Header("Settings")]
        [SerializeField] private Slider _musicSlider;
        [SerializeField] private Slider _sfxSlider;
        [SerializeField] private Toggle _fullscreenToggle;

        [Header("Currency Displays")]
        [SerializeField] private Text _goldText;
        [SerializeField] private Text _diamondText;
        [SerializeField] private Text _staminaText;
        [SerializeField] private Text _playerLevelText;
        [SerializeField] private Slider _playerExpSlider;

        [Header("Exchange")]
        [SerializeField] private Button _exchangeButton;
        [SerializeField] private ExchangePanel _exchangePanel;

        [Header("Level Data")]
        [SerializeField] private LevelData[] _levels;

        private void Start()
        {
            ShowMainPanel();
            LoadSettings();
            UpdatePlayerLevelDisplay();

            if (_exchangeButton != null)
                _exchangeButton.onClick.AddListener(OnExchangeClicked);
        }

        private void OnEnable()
        {
            var wallet = PlayerWallet.Instance;
            if (wallet != null)
            {
                wallet.OnGoldChanged += UpdateGold;
                wallet.OnDiamondChanged += UpdateDiamond;
                wallet.OnStaminaChanged += UpdateStamina;
                UpdateGold(wallet.Gold);
                UpdateDiamond(wallet.Diamond);
                UpdateStamina(wallet.Stamina);
            }

            var levelSystem = PlayerLevelSystem.Instance;
            if (levelSystem != null)
            {
                levelSystem.OnLevelChanged += UpdateLevelText;
                levelSystem.OnExpChanged += UpdateExpSlider;
                UpdatePlayerLevelDisplay();
            }
        }

        private void OnDisable()
        {
            var wallet = PlayerWallet.Instance;
            if (wallet != null)
            {
                wallet.OnGoldChanged -= UpdateGold;
                wallet.OnDiamondChanged -= UpdateDiamond;
                wallet.OnStaminaChanged -= UpdateStamina;
            }

            var levelSystem = PlayerLevelSystem.Instance;
            if (levelSystem != null)
            {
                levelSystem.OnLevelChanged -= UpdateLevelText;
                levelSystem.OnExpChanged -= UpdateExpSlider;
            }
        }

        private void UpdateGold(int amount) { if (_goldText != null) _goldText.text = amount.ToString(); }
        private void UpdateDiamond(int amount) { if (_diamondText != null) _diamondText.text = amount.ToString(); }
        private void UpdateStamina(int amount) { if (_staminaText != null) _staminaText.text = amount.ToString(); }

        public void ShowMainPanel()
        {
            if (_mainPanel != null) _mainPanel.SetActive(true);
            if (_levelSelectPanel != null) _levelSelectPanel.SetActive(false);
            if (_settingsPanel != null) _settingsPanel.SetActive(false);
        }

        public void ShowLevelSelect()
        {
            if (_mainPanel != null) _mainPanel.SetActive(false);
            if (_levelSelectPanel != null) _levelSelectPanel.SetActive(true);
            if (_settingsPanel != null) _settingsPanel.SetActive(false);

            GenerateLevelButtons();
        }

        public void ShowSettings()
        {
            if (_mainPanel != null) _mainPanel.SetActive(false);
            if (_levelSelectPanel != null) _levelSelectPanel.SetActive(false);
            if (_settingsPanel != null) _settingsPanel.SetActive(true);
        }

        public void StartLevel(int levelIndex)
        {
            if (levelIndex >= 0 && levelIndex < _levels.Length)
            {
                SceneManager.LoadScene(_levels[levelIndex].sceneName);
            }
        }

        public void QuitGame()
        {
#if UNITY_EDITOR
            UnityEditor.EditorApplication.isPlaying = false;
#else
            Application.Quit();
#endif
        }

        private void OnExchangeClicked()
        {
            if (_exchangePanel != null)
                _exchangePanel.Show();
        }

        private void GenerateLevelButtons()
        {
            if (_levelButtonContainer == null || _levelButtonPrefab == null) return;

            foreach (Transform child in _levelButtonContainer)
            {
                Destroy(child.gameObject);
            }

            for (int i = 0; i < _levels.Length; i++)
            {
                GameObject buttonObj = Instantiate(_levelButtonPrefab, _levelButtonContainer);
                LevelButton levelButton = buttonObj.GetComponent<LevelButton>();

                if (levelButton != null)
                {
                    levelButton.Setup(_levels[i], i, this);
                }
            }
        }

        #region Settings

        public void OnMusicVolumeChanged(float value)
        {
            PlayerPrefs.SetFloat("MusicVolume", value);
            PlayerPrefs.Save();
        }

        public void OnSFXVolumeChanged(float value)
        {
            PlayerPrefs.SetFloat("SFXVolume", value);
            PlayerPrefs.Save();
        }

        public void OnFullscreenToggled(bool isFullscreen)
        {
            Screen.fullScreen = isFullscreen;
            PlayerPrefs.SetInt("Fullscreen", isFullscreen ? 1 : 0);
            PlayerPrefs.Save();
        }

        private void LoadSettings()
        {
            if (_musicSlider != null)
            {
                _musicSlider.value = PlayerPrefs.GetFloat("MusicVolume", 1f);
            }
            if (_sfxSlider != null)
            {
                _sfxSlider.value = PlayerPrefs.GetFloat("SFXVolume", 1f);
            }
            if (_fullscreenToggle != null)
            {
                _fullscreenToggle.isOn = PlayerPrefs.GetInt("Fullscreen", 1) == 1;
            }
        }

        #endregion

        #region Player Level Display

        private void UpdatePlayerLevelDisplay()
        {
            var levelSystem = PlayerLevelSystem.Instance;
            if (levelSystem == null) return;

            UpdateLevelText(levelSystem.Level);
            UpdateExpSlider(levelSystem.CurrentExp, levelSystem.ExpToNextLevel);
        }

        private void UpdateLevelText(int level)
        {
            if (_playerLevelText != null)
                _playerLevelText.text = $"Lv.{level}";
        }

        private void UpdateExpSlider(int currentExp, int expToNext)
        {
            if (_playerExpSlider != null)
            {
                _playerExpSlider.maxValue = expToNext;
                _playerExpSlider.value = currentExp;
            }
        }

        #endregion
    }
}

using UnityEngine;
using UnityEngine.UI;
using System.Collections;
using System.Collections.Generic;
using TowerDefense.Data;
using TowerDefense.Core;

namespace TowerDefense.UI
{
    public class ShopPanel : MonoBehaviour
    {
        [Header("Panel")]
        [SerializeField] private GameObject _shopPanel;
        [SerializeField] private Button _closeButton;
        [SerializeField] private Image _dimOverlay;  // 半透明遮罩

        [Header("Currency Display")]
        [SerializeField] private Text _goldAmountText;
        [SerializeField] private Text _diamondAmountText;

        [Header("Tabs")]
        [SerializeField] private Button _tabResource;
        [SerializeField] private Button _tabHero;
        [SerializeField] private Button _tabTower;
        [SerializeField] private Button _tabSpecial;
        [SerializeField] private GameObject _tabIndicator;  // 滑动指示器
        [SerializeField] private Color _tabActiveColor = new Color(1f, 0.85f, 0.3f, 1f);
        [SerializeField] private Color _tabInactiveColor = new Color(0.6f, 0.6f, 0.6f, 1f);

        [Header("Content")]
        [SerializeField] private Transform _itemContainer;
        [SerializeField] private GameObject _shopItemPrefab;
        [Header("Confirm Dialog")]
        [SerializeField] private GameObject _confirmDialog;
        [SerializeField] private Text _confirmTitleText;
        [SerializeField] private Text _confirmDescText;
        [SerializeField] private Text _confirmPriceText;
        [SerializeField] private Button _confirmBuyButton;
        [SerializeField] private Button _confirmCancelButton;

        [Header("Feedback")]
        [SerializeField] private GameObject _feedbackPanel;
        [SerializeField] private Text _feedbackText;
        [SerializeField] private float _feedbackDuration = 1.5f;

        [Header("Data")]
        [SerializeField] private string _jsonPath = "Data/ShopItems";

        private ShopData _shopData;
        private ShopCategory _currentCategory;
        private ShopItemData _pendingBuyItem;
        private List<GameObject> _spawnedItems = new List<GameObject>();
        private Dictionary<ShopCategory, Button> _tabButtons = new Dictionary<ShopCategory, Button>();
        private Dictionary<ShopCategory, Vector3> _tabPositions = new Dictionary<ShopCategory, Vector3>();
        private GameObject _torchRoot;
        private MovingClouds _clouds;
        private ParticleSystem _snowParticles;
        private int _snowOriginalSortOrder;
        private Coroutine _feedbackCoroutine;

        private void Awake()
        {
            _tabButtons[ShopCategory.Resource] = _tabResource;
            _tabButtons[ShopCategory.Hero] = _tabHero;
            _tabButtons[ShopCategory.Tower] = _tabTower;
            _tabButtons[ShopCategory.Special] = _tabSpecial;

            if (_closeButton != null)
                _closeButton.onClick.AddListener(CloseShop);

            foreach (var kvp in _tabButtons)
            {
                if (kvp.Value != null)
                {
                    var cat = kvp.Key;
                    kvp.Value.onClick.AddListener(() => SwitchTab(cat));
                    // 记录每个Tab的位置用于指示器滑动
                    _tabPositions[cat] = kvp.Value.transform.localPosition;
                }
            }

            // 确认弹窗按钮
            if (_confirmBuyButton != null)
                _confirmBuyButton.onClick.AddListener(OnConfirmBuy);
            if (_confirmCancelButton != null)
                _confirmCancelButton.onClick.AddListener(OnCancelBuy);

            _torchRoot = GameObject.Find("火把");

            GameObject bgObj = GameObject.Find("背景");
            if (bgObj != null)
            {
                _clouds = bgObj.GetComponent<MovingClouds>();
                _snowParticles = bgObj.GetComponentInChildren<ParticleSystem>();
                if (_snowParticles != null)
                {
                    var renderer = _snowParticles.GetComponent<ParticleSystemRenderer>();
                    if (renderer != null)
                        _snowOriginalSortOrder = renderer.sortingOrder;
                }
            }

            LoadShopData();
        }

        private void Start()
        {
            if (_shopPanel != null)
                _shopPanel.SetActive(false);
            if (_confirmDialog != null)
                _confirmDialog.SetActive(false);
            if (_feedbackPanel != null)
                _feedbackPanel.SetActive(false);
        }

        private void LoadShopData()
        {
            var jsonFile = Resources.Load<TextAsset>(_jsonPath);
            if (jsonFile != null)
            {
                _shopData = JsonUtility.FromJson<ShopData>(jsonFile.text);
                Debug.Log($"[ShopPanel] Loaded {_shopData.items.Length} items from JSON");
            }
            else
            {
                Debug.LogError($"[ShopPanel] Failed to load JSON: Resources/{_jsonPath}");
                _shopData = new ShopData { items = new ShopItemData[0] };
            }
        }

        public void OpenShop()
        {
            if (_shopPanel != null)
                _shopPanel.SetActive(true);

            // 半透明遮罩
            if (_dimOverlay != null)
            {
                _dimOverlay.gameObject.SetActive(true);
                _dimOverlay.color = new Color(0, 0, 0, 0.6f);
            }

            if (_torchRoot != null)
                _torchRoot.SetActive(false);

            if (_clouds != null)
                _clouds.IsPaused = true;

            if (_snowParticles != null)
            {
                var renderer = _snowParticles.GetComponent<ParticleSystemRenderer>();
                if (renderer != null)
                    renderer.sortingOrder = -10;
                _snowParticles.Pause(true);
            }

            LoadShopData();
            UpdateCurrencyDisplay();
            SwitchTab(ShopCategory.Resource);
        }

        public void CloseShop()
        {
            if (_shopPanel != null)
                _shopPanel.SetActive(false);

            if (_dimOverlay != null)
                _dimOverlay.gameObject.SetActive(false);

            if (_torchRoot != null)
                _torchRoot.SetActive(true);

            if (_clouds != null)
                _clouds.IsPaused = false;

            if (_snowParticles != null)
            {
                var renderer = _snowParticles.GetComponent<ParticleSystemRenderer>();
                if (renderer != null)
                    renderer.sortingOrder = _snowOriginalSortOrder;
                _snowParticles.Play(true);
            }
        }

        private void UpdateCurrencyDisplay()
        {
            var wallet = PlayerWallet.Instance;
            if (wallet != null)
            {
                if (_goldAmountText != null)
                    _goldAmountText.text = wallet.Gold.ToString();
                if (_diamondAmountText != null)
                    _diamondAmountText.text = wallet.Diamond.ToString();
            }
        }

        private void SwitchTab(ShopCategory category)
        {
            _currentCategory = category;
            UpdateTabVisuals();
            MoveTabIndicator(category);
            RefreshItemList();
        }

        private void UpdateTabVisuals()
        {
            foreach (var kvp in _tabButtons)
            {
                if (kvp.Value == null) continue;
                var colors = kvp.Value.colors;
                colors.normalColor = kvp.Key == _currentCategory ? _tabActiveColor : _tabInactiveColor;
                colors.selectedColor = colors.normalColor;
                colors.highlightedColor = kvp.Key == _currentCategory ? _tabActiveColor : new Color(0.8f, 0.8f, 0.8f, 1f);
                kvp.Value.colors = colors;
            }
        }

        private void MoveTabIndicator(ShopCategory category)
        {
            if (_tabIndicator == null || !_tabPositions.ContainsKey(category)) return;
            StartCoroutine(AnimateTabIndicator(_tabPositions[category]));
        }

        private IEnumerator AnimateTabIndicator(Vector3 targetPos)
        {
            Vector3 startPos = _tabIndicator.transform.localPosition;
            float duration = 0.2f;
            float elapsed = 0f;

            while (elapsed < duration)
            {
                elapsed += Time.deltaTime;
                float t = elapsed / duration;
                // ease-out
                t = 1f - (1f - t) * (1f - t);
                _tabIndicator.transform.localPosition = Vector3.Lerp(startPos, targetPos, t);
                yield return null;
            }

            _tabIndicator.transform.localPosition = targetPos;
        }

        private void RefreshItemList()
        {
            foreach (var item in _spawnedItems)
            {
                if (item != null) Destroy(item);
            }
            _spawnedItems.Clear();

            if (_itemContainer == null || _shopItemPrefab == null)
            {
                Debug.LogWarning("[ShopPanel] Item container or prefab is null");
                return;
            }

            foreach (var itemData in _shopData.items)
            {
                if (itemData.category != _currentCategory) continue;

                GameObject itemObj = Instantiate(_shopItemPrefab, _itemContainer);
                _spawnedItems.Add(itemObj);

                var shopItemUI = itemObj.GetComponent<ShopItemUI>();
                if (shopItemUI != null)
                {
                    shopItemUI.Setup(itemData, this);
                }
            }
        }

        /// <summary>
        /// 点击购买时，先弹出确认框
        /// </summary>
        public void OnBuyClicked(ShopItemData itemData)
        {
            if (itemData.isLimited && itemData.purchasedCount >= itemData.limitCount)
            {
                ShowFeedback("已达购买上限!");
                return;
            }

            _pendingBuyItem = itemData;
            ShowConfirmDialog(itemData);
        }

        private void ShowConfirmDialog(ShopItemData itemData)
        {
            if (_confirmDialog == null)
            {
                // 没有确认弹窗则直接购买
                ExecuteBuy(itemData);
                return;
            }

            if (_confirmTitleText != null)
                _confirmTitleText.text = $"购买 {itemData.name}?";

            if (_confirmDescText != null)
            {
                string rewardText = ShopItemUI.BuildRewardText(itemData);
                _confirmDescText.text = string.IsNullOrEmpty(rewardText) ? itemData.description : $"获得: {rewardText}";
            }

            if (_confirmPriceText != null)
            {
                int price = itemData.discount > 0
                    ? itemData.price * (100 - itemData.discount) / 100
                    : itemData.price;

                if (itemData.currencyType == CurrencyType.Free)
                {
                    _confirmPriceText.text = "免费领取";
                    _confirmPriceText.color = Color.green;
                }
                else
                {
                    string symbol = GetCurrencySymbol(itemData.currencyType);
                    _confirmPriceText.text = $"花费: {symbol} {price}";
                    _confirmPriceText.color = Color.white;
                }
            }

            _confirmDialog.SetActive(true);
        }

        private void OnConfirmBuy()
        {
            if (_confirmDialog != null)
                _confirmDialog.SetActive(false);

            if (_pendingBuyItem != null)
            {
                ExecuteBuy(_pendingBuyItem);
                _pendingBuyItem = null;
            }
        }

        private void OnCancelBuy()
        {
            if (_confirmDialog != null)
                _confirmDialog.SetActive(false);
            _pendingBuyItem = null;
        }

        private void ExecuteBuy(ShopItemData itemData)
        {
            int price = itemData.discount > 0
                ? itemData.price * (100 - itemData.discount) / 100
                : itemData.price;

            var wallet = PlayerWallet.Instance;
            if (wallet == null)
            {
                Debug.LogWarning("[ShopPanel] PlayerWallet not found");
                return;
            }

            bool success = itemData.currencyType switch
            {
                CurrencyType.Gold => wallet.SpendGold(price),
                CurrencyType.Diamond => wallet.SpendDiamond(price),
                CurrencyType.Free => true,
                _ => false
            };

            if (!success)
            {
                string curName = itemData.currencyType switch
                {
                    CurrencyType.Gold => "金币不足",
                    CurrencyType.Diamond => "钻石不足",
                    _ => "无法购买"
                };
                ShowFeedback(curName);
                return;
            }

            Debug.Log($"[ShopPanel] 购买成功: {itemData.name}, 花费: {price}");

            // 发放奖励
            if (itemData.rewardGold > 0)
                wallet.AddGold(itemData.rewardGold);
            if (itemData.rewardDiamond > 0)
                wallet.AddDiamond(itemData.rewardDiamond);
            if (itemData.rewardStamina > 0)
                wallet.AddStamina(itemData.rewardStamina);

            itemData.purchasedCount++;

            ShowFeedback($"购买成功! {itemData.name}");
            UpdateCurrencyDisplay();
            RefreshItemList();
        }

        private void ShowFeedback(string message)
        {
            if (_feedbackPanel == null || _feedbackText == null) return;

            if (_feedbackCoroutine != null)
                StopCoroutine(_feedbackCoroutine);

            _feedbackCoroutine = StartCoroutine(ShowFeedbackCoroutine(message));
        }

        private IEnumerator ShowFeedbackCoroutine(string message)
        {
            _feedbackPanel.SetActive(true);
            _feedbackText.text = message;

            // 淡入
            var canvasGroup = _feedbackPanel.GetComponent<CanvasGroup>();
            if (canvasGroup != null)
            {
                canvasGroup.alpha = 0f;
                float fadeIn = 0.2f;
                float t = 0f;
                while (t < fadeIn)
                {
                    t += Time.deltaTime;
                    canvasGroup.alpha = Mathf.Lerp(0f, 1f, t / fadeIn);
                    yield return null;
                }
                canvasGroup.alpha = 1f;

                // 停留
                yield return new WaitForSeconds(_feedbackDuration);

                // 淡出
                float fadeOut = 0.3f;
                t = 0f;
                while (t < fadeOut)
                {
                    t += Time.deltaTime;
                    canvasGroup.alpha = Mathf.Lerp(1f, 0f, t / fadeOut);
                    yield return null;
                }
                canvasGroup.alpha = 0f;
            }
            else
            {
                yield return new WaitForSeconds(_feedbackDuration);
            }

            _feedbackPanel.SetActive(false);
            _feedbackCoroutine = null;
        }

        public static string GetCategoryName(ShopCategory category)
        {
            return category switch
            {
                ShopCategory.Resource => "资源",
                ShopCategory.Hero => "英雄",
                ShopCategory.Tower => "防御塔",
                ShopCategory.Special => "特惠",
                _ => "未知"
            };
        }

        public static string GetCurrencySymbol(CurrencyType type)
        {
            return type switch
            {
                CurrencyType.Gold => "🪙",
                CurrencyType.Diamond => "💎",
                CurrencyType.Free => "🎁",
                _ => ""
            };
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using TowerDefense.Data;
using TowerDefense.Tower;
using TowerDefense.Core;

namespace TowerDefense.UI
{
    public class TowerSelectPanel : MonoBehaviour
    {
        [Header("References")]
        [SerializeField] private GameObject _panel;
        [SerializeField] private Transform _towerButtonContainer;
        [SerializeField] private GameObject _towerButtonPrefab;
        [SerializeField] private Text _slotInfoText;

        [Header("Text Settings")]
        [SerializeField] private Font _buttonFont;


        [Header("Tower Data")]
        [SerializeField] private TowerData[] _availableTowers;

        private TowerSlot _currentSlot;
        private TowerData[] _towerDatas;

        private void Awake()
        {
            Debug.Log($"TowerSelectPanel Awake - _panel: {_panel != null}, _container: {_towerButtonContainer != null}, _prefab: {_towerButtonPrefab != null}, _text: {_slotInfoText != null}");

            if (_panel != null)
            {
                _panel.SetActive(true);
            }

            LoadTowerData();
            RefreshTowerButtons();
        }

        private void LoadTowerData()
        {
            if (_availableTowers != null && _availableTowers.Length > 0)
            {
                _towerDatas = _availableTowers;
            }
            else
            {
                _towerDatas = Resources.LoadAll<TowerData>("Data/Towers");

                if (_towerDatas.Length == 0)
                {
                    _towerDatas = Resources.LoadAll<TowerData>("Data");
                }
            }
        }

        public void Show(TowerSlot slot)
        {
            _currentSlot = slot;

            if (_panel == null)
            {
                Debug.LogWarning("⚠️ TowerSelectPanel 的 _panel 字段未设置！");
                return;
            }

            RefreshTowerButtons();
            _panel.SetActive(true);
        }

        public void Hide()
        {
            _currentSlot = null;

            if (_panel != null)
            {
                _panel.SetActive(false);
            }
        }

        private void RefreshTowerButtons()
        {
            foreach (Transform child in _towerButtonContainer)
            {
                Destroy(child.gameObject);
            }

            foreach (var towerData in _towerDatas)
            {
                CreateTowerButton(towerData);
            }
        }

        private void CreateTowerButton(TowerData towerData)
        {
            GameObject buttonObj;

            if (_towerButtonPrefab == null)
            {
                buttonObj = new GameObject($"TowerButton_{towerData.towerName}");
                buttonObj.transform.SetParent(_towerButtonContainer, false);

                Button button = buttonObj.AddComponent<Button>();
                Image bgImage = buttonObj.AddComponent<Image>();
                bgImage.color = new Color(0.4f, 0.4f, 0.6f);

                RectTransform buttonRect = buttonObj.GetComponent<RectTransform>();
                buttonRect.sizeDelta = new Vector2(70, 85);

                if (towerData.icon != null)
                {
                    GameObject iconObj = new GameObject("Icon");
                    iconObj.transform.SetParent(buttonObj.transform, false);

                    Image iconImage = iconObj.AddComponent<Image>();
                    iconImage.sprite = towerData.icon;
                    iconImage.preserveAspect = true;

                    RectTransform iconRect = iconObj.GetComponent<RectTransform>();
                    iconRect.anchorMin = new Vector2(0.5f, 0.4f);
                    iconRect.anchorMax = new Vector2(0.5f, 1f);
                    iconRect.offsetMin = new Vector2(-30, 0);
                    iconRect.offsetMax = new Vector2(30, 0);
                }

                GameObject textObj = new GameObject("Text");
                textObj.transform.SetParent(buttonObj.transform, false);

                Outline outline = textObj.AddComponent<Outline>();
                outline.effectColor = Color.black;
                outline.effectDistance = new Vector2(2, -2);

                Text text = textObj.AddComponent<Text>();
                text.text = $"{GetTowerPrice(towerData)}";

                if (_buttonFont != null)
                {
                    text.font = _buttonFont;
                }

                text.fontSize = 26;
                text.fontStyle = FontStyle.Bold;
                text.alignment = TextAnchor.LowerCenter;
                text.color = new Color(1f, 0.9f, 0f);
                text.horizontalOverflow = HorizontalWrapMode.Overflow;
                text.verticalOverflow = VerticalWrapMode.Overflow;

                RectTransform textRect = textObj.GetComponent<RectTransform>();
                textRect.anchorMin = Vector2.zero;
                textRect.anchorMax = new Vector2(1f, 0.35f);
                textRect.offsetMin = Vector2.zero;
                textRect.offsetMax = Vector2.zero;

                bool canAfford = GameManager.Instance.HasEnoughGold(GetTowerPrice(towerData));
            button.interactable = canAfford;
            Debug.Log($"🔘 [动态按钮] 添加点击监听器: {towerData.towerName}");
            button.onClick.AddListener(() => {
                Debug.Log($"🖱️ [动态按钮] Lambda被调用！");
                OnTowerSelected(towerData);
            });
            Debug.Log($"🔘 [动态按钮] 点击监听器已添加！");

            if (!canAfford)
                {
                    bgImage.color = new Color(0.3f, 0.3f, 0.3f);
                }
            }
            else
            {
                buttonObj = Instantiate(_towerButtonPrefab, _towerButtonContainer);
                buttonObj.name = $"TowerButton_{towerData.towerName}";

                TowerButton towerButton = buttonObj.GetComponent<TowerButton>();
                if (towerButton != null)
                {
                    towerButton.Initialize(towerData, this);
                    Debug.Log($"📌 TowerButton 组件已初始化: {towerData.towerName}");
                }
                else
                {
                    Debug.LogWarning($"⚠️ TowerButton 预制体没有 TowerButton 组件，使用手动设置");
                    SetupButtonManually(buttonObj, towerData);
                }
            }
        }

        private int GetTowerPrice(TowerData towerData)
        {
            if (towerData.levels != null && towerData.levels.Length > 0)
            {
                return towerData.levels[0].cost;
            }
            return 0;
        }

        private void SetupButtonManually(GameObject buttonObj, TowerData towerData)
        {
            Text nameText = buttonObj.GetComponentInChildren<Text>();
            if (nameText != null)
            {
                nameText.text = towerData.towerName;
            }

            Image[] images = buttonObj.GetComponentsInChildren<Image>();
            foreach (var img in images)
            {
                if (img.gameObject != buttonObj && towerData.icon != null && img.sprite == null)
                {
                    img.sprite = towerData.icon;
                    img.preserveAspect = true;
                    break;
                }
            }

            Button button = buttonObj.GetComponent<Button>();
            if (button != null)
            {
                button.onClick.AddListener(() => OnTowerSelected(towerData));

                bool canAfford = GameManager.Instance.HasEnoughGold(towerData.levels[0].cost);
                button.interactable = canAfford;
            }
        }

        public void OnTowerSelected(TowerData towerData)
        {
            Debug.Log($"📞 OnTowerSelected 被调用！塔: {towerData?.towerName}, _currentSlot: {_currentSlot != null}");

            if (_currentSlot == null || towerData == null)
            {
                Debug.LogError("❌ _currentSlot 或 towerData 是 null！");
                return;
            }

            Debug.Log($"📦 准备放置塔: {towerData.towerName}, 消耗金币: {towerData.levels[0].cost}");

            bool success = _currentSlot.PlaceTower(towerData);
            Debug.Log($"📦 PlaceTower 返回: {success}");

            if (success)
            {
                Debug.Log("✅ 塔放置成功！");
                // 面板常驻，不隐藏；刷新按钮状态
                _currentSlot = null;
                UpdateButtonStates();
            }
            else
            {
                Debug.LogWarning("⚠️ 塔放置失败！");
            }
        }

        public void UpdateButtonStates()
        {
            foreach (Transform child in _towerButtonContainer)
            {
                TowerButton button = child.GetComponent<TowerButton>();
                if (button != null)
                {
                    button.UpdateState();
                }
            }
        }

        private void OnEnable()
        {
            EventBus.Subscribe<GoldChangedEvent>(OnGoldChanged);
        }

        private void OnDisable()
        {
            EventBus.Unsubscribe<GoldChangedEvent>(OnGoldChanged);
        }

        private void OnGoldChanged(GoldChangedEvent e)
        {
            UpdateButtonStates();
        }
    }

    public class TowerButton : MonoBehaviour
    {
        [SerializeField] private Text _nameText;
        [SerializeField] private Text _costText;
        [SerializeField] private Text _damageText;
        [SerializeField] private Text _rangeText;
        [SerializeField] private Image _icon;

        private TowerData _towerData;
        private TowerSelectPanel _panel;

        public void Initialize(TowerData towerData, TowerSelectPanel panel)
        {
            _towerData = towerData;
            _panel = panel;

            if (_nameText != null)
            {
                _nameText.text = towerData.towerName;
            }

            TowerData.TowerStats stats = towerData.levels[0];
            if (_costText != null)
            {
                _costText.text = $"{stats.cost} G";
            }

            if (_damageText != null)
            {
                _damageText.text = $"伤害: {stats.damage}";
            }

            if (_rangeText != null)
            {
                _rangeText.text = $"范围: {stats.attackRange}";
            }

            if (towerData.icon != null)
            {
                if (_icon != null)
                {
                    _icon.sprite = towerData.icon;
                    _icon.gameObject.SetActive(true);
                }

                Image[] allImages = GetComponentsInChildren<Image>();
                foreach (var img in allImages)
                {
                    if (img.gameObject != gameObject && img.sprite == null)
                    {
                        img.sprite = towerData.icon;
                        img.preserveAspect = true;
                        break;
                    }
                }
            }
            else
            {
                if (_icon != null)
                {
                    _icon.gameObject.SetActive(false);
                }
            }

            UpdateState();

            Button button = GetComponent<Button>();
            if (button != null)
            {
                Debug.Log($"🔘 找到Button组件，准备添加点击监听器...");
                button.onClick.AddListener(OnClicked);
                Debug.Log($"🔘 点击监听器已添加！当前监听器数量: {button.onClick.GetPersistentEventCount()}");
            }
            else
            {
                Debug.LogError("❌ 找不到Button组件！");
            }
        }

        public void UpdateState()
        {
            Button button = GetComponent<Button>();
            if (button != null)
            {
                bool canAfford = GameManager.Instance.HasEnoughGold(_towerData.levels[0].cost);
                button.interactable = canAfford;

                Image image = GetComponent<Image>();
                if (image != null)
                {
                    image.color = canAfford ? Color.white : Color.grey;
                }
            }
        }

        private void OnClicked()
        {
            Debug.Log($"🖱️ TowerButton.OnClicked 被调用！塔: {_towerData?.towerName}, panel: {_panel != null}");

            if (_panel != null)
            {
                Debug.Log($"📞 调用 _panel.OnTowerSelected...");
                _panel.OnTowerSelected(_towerData);
            }
            else
            {
                Debug.LogError("❌ _panel 是 null！");
            }
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using UnityEngine.SceneManagement;
using TowerDefense.Core;

namespace TowerDefense.UI
{
    public class VictoryPanel : MonoBehaviour
    {
        [Header("Title")]
        [SerializeField] private Text _titleText;

        [Header("Stars")]
        [SerializeField] private Image[] _starImages = new Image[3];
        [SerializeField] private Sprite _starFilledSprite;
        [SerializeField] private Sprite _starEmptySprite;

        [Header("Stats")]
        [SerializeField] private Text _killCountText;
        [SerializeField] private Text _goldText;
        [SerializeField] private Text _waveText;

        [Header("Buttons")]
        [SerializeField] private Button _restartButton;
        [SerializeField] private Button _nextLevelButton;
        [SerializeField] private Button _mainMenuButton;

        private void Awake()
        {
            if (_restartButton != null)
                _restartButton.onClick.AddListener(OnRestartClicked);
            if (_nextLevelButton != null)
                _nextLevelButton.onClick.AddListener(OnNextLevelClicked);
            if (_mainMenuButton != null)
                _mainMenuButton.onClick.AddListener(OnMainMenuClicked);
        }

        private void OnDestroy()
        {
            if (_restartButton != null)
                _restartButton.onClick.RemoveListener(OnRestartClicked);
            if (_nextLevelButton != null)
                _nextLevelButton.onClick.RemoveListener(OnNextLevelClicked);
            if (_mainMenuButton != null)
                _mainMenuButton.onClick.RemoveListener(OnMainMenuClicked);
        }

        public void ShowVictory()
        {
            gameObject.SetActive(true);
            UpdateStats();
            UpdateStars();
        }

        public void HideVictory()
        {
            gameObject.SetActive(false);
        }

        private void UpdateStats()
        {
            var gm = GameManager.Instance;
            if (gm == null) return;

            if (_killCountText != null)
                _killCountText.text = gm.EnemiesKilled.ToString();
            if (_goldText != null)
                _goldText.text = gm.CurrentGold.ToString();
            if (_waveText != null)
                _waveText.text = $"{gm.CurrentWave}/{gm.TotalWaves}";
        }

        private void UpdateStars()
        {
            var gm = GameManager.Instance;
            if (gm == null) return;

            int starCount = CalculateStars(gm);
            for (int i = 0; i < _starImages.Length; i++)
            {
                if (_starImages[i] == null) continue;
                if (_starFilledSprite != null && _starEmptySprite != null)
                {
                    _starImages[i].sprite = i < starCount ? _starFilledSprite : _starEmptySprite;
                }
                else
                {
                    _starImages[i].color = i < starCount
                        ? new Color(1f, 0.85f, 0f, 1f)
                        : new Color(0.3f, 0.3f, 0.3f, 0.5f);
                }
            }
        }

        private int CalculateStars(GameManager gm)
        {
            float lifeRatio = (float)gm.CurrentLife / 20f;
            if (lifeRatio >= 0.7f) return 3;
            if (lifeRatio >= 0.4f) return 2;
            return 1;
        }

        private void OnRestartClicked()
        {
            HideVictory();
            GameManager.Instance.RestartGame();
        }

        private void OnNextLevelClicked()
        {
            HideVictory();
            int nextIndex = GameManager.Instance.CurrentLevelData != null ? 1 : 0;
            var levels = GameManager.Instance.Levels;
            if (levels != null && nextIndex < levels.Length)
            {
                GameManager.Instance.LoadLevel(nextIndex);
            }
            else
            {
                SceneManager.LoadScene(SceneManager.GetActiveScene().name);
            }
        }

        private void OnMainMenuClicked()
        {
            HideVictory();
            if (ModuleModeDetector.IsModuleMode)
            {
                // 从家园进入时，返回家园
                SceneManager.LoadScene("HomeScene");
            }
            else
            {
                SceneManager.LoadScene("MainMenu");
            }
        }
    }
}

