using UnityEngine;
using UnityEngine.UI;

// ============================================================
// Fantasy Tower Defense HUD Builder
// 奇幻塔防游戏精美HUD界面构建器
// ============================================================

public static class FantasyHUDBuilder
{
    // --- Color Palette (Medieval Fantasy) ---
    static readonly Color COL_GOLD       = new Color(1f, 0.84f, 0f, 1f);       // 金色
    static readonly Color COL_DARK_BG    = new Color(0.12f, 0.08f, 0.06f, 0.92f); // 深棕背景
    static readonly Color COL_PANEL_BG   = new Color(0.15f, 0.10f, 0.07f, 0.88f); // 面板背景
    static readonly Color COL_FRAME     = new Color(0.55f, 0.40f, 0.18f, 1f);  // 边框金棕
    static readonly Color COL_TEXT       = new Color(1f, 0.95f, 0.8f, 1f);     // 暖白文字
    static readonly Color COL_GOLD_TEXT  = new Color(1f, 0.85f, 0.2f, 1f);     // 金色文字
    static readonly Color COL_RED        = new Color(0.9f, 0.2f, 0.15f, 1f);   // 红色
    static readonly Color COL_GREEN      = new Color(0.2f, 0.8f, 0.3f, 1f);    // 绿色
    static readonly Color COL_BLUE        = new Color(0.3f, 0.5f, 0.95f, 1f);   // 蓝色
    static readonly Color COL_BUTTON_N   = new Color(0.45f, 0.30f, 0.12f, 1f); // 按钮正常
    static readonly Color COL_BUTTON_H   = new Color(0.60f, 0.42f, 0.18f, 1f); // 按钮高亮
    static readonly Color COL_BUTTON_P   = new Color(0.30f, 0.18f, 0.06f, 1f); // 按钮按下
    static readonly Color COL_SHADOW      = new Color(0f, 0f, 0f, 0.6f);        // 阴影

    static Font _font;

    public static void Build()
    {
        _font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");

        // Remove old HUD if exists
        var old = GameObject.Find("--- FANTASY HUD ---");
        if (old != null) Object.DestroyImmediate(old);

        // === ROOT ===
        var root = new GameObject("--- FANTASY HUD ---");
        var rootCanvas = root.AddComponent<Canvas>();
        rootCanvas.renderMode = RenderMode.ScreenSpaceOverlay;
        root.AddComponent<CanvasScaler>().uiScaleMode = CanvasScaler.ScaleMode.ScaleWithScreenSize;
        root.AddComponent<GraphicRaycaster>();
        var rootRect = root.GetComponent<RectTransform>();
        rootRect.anchorMin = Vector2.zero;
        rootRect.anchorMax = Vector2.one;
        rootRect.offsetMin = rootRect.offsetMax = Vector2.zero;

        // ===== TOP BAR =====
        var topBar = CreatePanel(root.transform, "TopBar",
            new Vector2(0, 1), new Vector2(1, 1),   // anchor top stretch
            new Vector2(0, -80), new Vector2(0, 0),  // offset: height 80
            COL_DARK_BG);
        AddFrameBorder(topBar, COL_FRAME, 3);

        // Left group: Gold + Diamond
        var leftGroup = CreateHorizontalGroup(topBar.transform, "LeftResources",
            new Vector2(0, 0.5f), new Vector2(0, 0.5f),
            new Vector2(20, -25), new Vector2(420, 25),
            12f, true, true, true);

        // Gold display
        var goldIcon = CreateIcon(leftGroup.transform, "GoldIcon",
            "Assets/Art/UI/Icons/icon_gold.png",
            new Vector2(0, 0.5f), new Vector2(0, 0.5f),
            new Vector2(0, 0), new Vector2(36, 36));
        var goldText = CreateLabel(leftGroup.transform, "GoldText", "9999",
            22, FontStyle.Bold, COL_GOLD_TEXT, TextAnchor.MiddleLeft,
            new Vector2(0, 0.5f), new Vector2(1, 0.5f),
            new Vector2(36, -12), new Vector2(100, 24));
        AddOutline(goldText, Color.black, new Vector2(2, -2));

        // Diamond display
        var diamondIcon = CreateIcon(leftGroup.transform, "DiamondIcon",
            "Assets/Art/UI/Icons/icon_diamond 2.png",
            new Vector2(0, 0.5f), new Vector2(0, 0.5f),
            new Vector2(120, 0), new Vector2(36, 36));
        var diamondText = CreateLabel(leftGroup.transform, "DiamondText", "888",
            22, FontStyle.Bold, COL_BLUE, TextAnchor.MiddleLeft,
            new Vector2(0, 0.5f), new Vector2(1, 0.5f),
            new Vector2(156, -12), new Vector2(80, 24));
        AddOutline(diamondText, Color.black, new Vector2(2, -2));

        // Center group: Wave info
        var centerGroup = CreatePanel(topBar.transform, "WaveInfo",
            new Vector2(0.5f, 0.5f), new Vector2(0.5f, 0.5f),
            new Vector2(-160, -25), new Vector2(160, 25),
            new Color(0,0,0,0));

        var waveIcon = CreateIcon(centerGroup.transform, "WaveIcon",
            "Assets/Art/UI/Icons/icon_wave 1.png",
            new Vector2(0, 0.5f), new Vector2(0, 0.5f),
            new Vector2(-140, 0), new Vector2(32, 32));
        var waveText = CreateLabel(centerGroup.transform, "WaveText", "Wave 3/10",
            24, FontStyle.Bold, COL_TEXT, TextAnchor.MiddleCenter,
            new Vector2(0, 0.5f), new Vector2(1, 0.5f),
            new Vector2(-100, -14), new Vector2(200, 28));
        AddOutline(waveText, Color.black, new Vector2(2, -2));

        // Right group: Life + Controls
        var rightGroup = CreateHorizontalGroup(topBar.transform, "RightControls",
            new Vector2(1, 0.5f), new Vector2(1, 0.5f),
            new Vector2(-300, -25), new Vector2(-10, 25),
            8f, false, true, true);

        // Life display
        var heartIcon = CreateIcon(rightGroup.transform, "HeartIcon",
            "Assets/Art/UI/Icons/icon_heart 1.png",
            new Vector2(0, 0.5f), new Vector2(0, 0.5f),
            new Vector2(0, 0), new Vector2(32, 32));
        var lifeText = CreateLabel(rightGroup.transform, "LifeText", "20",
            22, FontStyle.Bold, COL_RED, TextAnchor.MiddleLeft,
            new Vector2(0, 0.5f), new Vector2(1, 0.5f),
            new Vector2(36, -12), new Vector2(50, 24));
        AddOutline(lifeText, Color.black, new Vector2(2, -2));

        // Pause button
        var pauseBtn = CreateGameButton(rightGroup.transform, "PauseBtn",
            "Assets/Art/UI/Icons/icon_pause.png",
            new Vector2(0, 0.5f), new Vector2(0, 0.5f),
            new Vector2(120, 0), new Vector2(40, 40),
            COL_BUTTON_N, COL_BUTTON_H, COL_BUTTON_P);

        // Speed button
        var speedBtn = CreateGameButton(rightGroup.transform, "SpeedBtn",
            "Assets/Art/UI/Icons/icon_speed.png",
            new Vector2(0, 0.5f), new Vector2(0, 0.5f),
            new Vector2(170, 0), new Vector2(40, 40),
            COL_BUTTON_N, COL_BUTTON_H, COL_BUTTON_P);
        var speedLabel = CreateLabel(speedBtn.transform, "SpeedLabel", "1x",
            14, FontStyle.Bold, COL_GOLD_TEXT, TextAnchor.MiddleCenter,
            new Vector2(0, 0), new Vector2(1, 1),
            new Vector2(0, -28), new Vector2(40, 16));
        AddOutline(speedLabel, Color.black, new Vector2(1, -1));

        // ===== TOWER SELECT BAR (Bottom) =====
        var towerBar = CreatePanel(root.transform, "TowerBar",
            new Vector2(0, 0), new Vector2(1, 0),
            new Vector2(0, 0), new Vector2(0, 100),
            COL_DARK_BG);
        AddFrameBorder(towerBar, COL_FRAME, 3);

        // Tower bar title
        var towerTitle = CreateLabel(towerBar.transform, "TowerBarTitle", "⚔ TOWERS ⚔",
            16, FontStyle.Bold, COL_GOLD, TextAnchor.MiddleCenter,
            new Vector2(0.5f, 1), new Vector2(0.5f, 1),
            new Vector2(-80, -20), new Vector2(160, 20));
        AddOutline(towerTitle, Color.black, new Vector2(1, -1));

        // Tower buttons container
        var towerContainer = CreateHorizontalGroup(towerBar.transform, "TowerButtons",
            new Vector2(0.5f, 0.5f), new Vector2(0.5f, 0.5f),
            new Vector2(-280, -20), new Vector2(280, 20),
            16f, true, true, false);

        // Sample tower buttons
        string[] towerNames = { "Archer", "Barracks", "Mage", "Cannon" };
        Color[] towerColors = { COL_GREEN, new Color(0.8f,0.5f,0.2f,1f), COL_BLUE, COL_RED };
        int[] towerCosts = { 70, 100, 120, 125 };

        for (int i = 0; i < towerNames.Length; i++)
        {
            var btn = CreateTowerButton(towerContainer.transform, towerNames[i], towerCosts[i], towerColors[i]);
        }

        // ===== START WAVE BUTTON (Right Side) =====
        var startWaveBtn = CreateFancyButton(root.transform, "StartWaveBtn",
            "⚔ START WAVE",
            new Vector2(1, 0.5f), new Vector2(1, 0.5f),
            new Vector2(-180, -10), new Vector2(-10, 10),
            new Color(0.7f, 0.15f, 0.1f, 1f),
            new Color(0.85f, 0.25f, 0.15f, 1f),
            new Color(0.5f, 0.1f, 0.05f, 1f),
            28, COL_GOLD_TEXT);
        AddOutline(startWaveBtn.GetComponentInChildren<Text>(), Color.black, new Vector2(2, -2));

        // ===== TOWER INFO PANEL (Right Side, above start wave) =====
        var towerInfo = CreatePanel(root.transform, "TowerInfoPanel",
            new Vector2(1, 0.5f), new Vector2(1, 0.5f),
            new Vector2(-200, 30), new Vector2(-10, 180),
            COL_PANEL_BG);
        towerInfo.SetActive(false); // Hidden by default
        AddFrameBorder(towerInfo, COL_FRAME, 3);

        var towerNameLabel = CreateLabel(towerInfo.transform, "TowerName", "Archer Tower",
            22, FontStyle.Bold, COL_GOLD_TEXT, TextAnchor.MiddleCenter,
            new Vector2(0, 1), new Vector2(1, 1),
