        go.transform.SetParent(parent, false);
        var rect = go.AddComponent<RectTransform>();
        rect.anchorMin = anchorMin;
        rect.anchorMax = anchorMax;
        rect.offsetMin = offsetMin;
        rect.offsetMax = offsetMax;

        var img = go.AddComponent<Image>();
        img.color = bgColor;
        img.raycastTarget = true;
        return go;
    }

    static void AddFrameBorder(GameObject panel, Color frameColor, int thickness)
    {
        var rect = panel.GetComponent<RectTransform>();
        float w = rect.rect.width;
        float h = rect.rect.height;

        // Top
        CreateBorderEdge(panel.transform, "Border_Top",
            new Vector2(0, 1), new Vector2(1, 1),
            new Vector2(0, -thickness), new Vector2(0, 0),
            frameColor);
        // Bottom
        CreateBorderEdge(panel.transform, "Border_Bottom",
            new Vector2(0, 0), new Vector2(1, 0),
            new Vector2(0, 0), new Vector2(0, thickness),
            frameColor);
        // Left
        CreateBorderEdge(panel.transform, "Border_Left",
            new Vector2(0, 0), new Vector2(0, 1),
            new Vector2(0, 0), new Vector2(thickness, 0),
            frameColor);
        // Right
        CreateBorderEdge(panel.transform, "Border_Right",
            new Vector2(1, 0), new Vector2(1, 1),
            new Vector2(-thickness, 0), new Vector2(0, 0),
            frameColor);
    }

    static void CreateBorderEdge(Transform parent, string name,
        Vector2 anchorMin, Vector2 anchorMax,
        Vector2 offsetMin, Vector2 offsetMax,
        Color color)
    {
        var go = new GameObject(name);
        go.transform.SetParent(parent, false);
        var rect = go.AddComponent<RectTransform>();
        rect.anchorMin = anchorMin;
        rect.anchorMax = anchorMax;
        rect.offsetMin = offsetMin;
        rect.offsetMax = offsetMax;
        var img = go.AddComponent<Image>();
        img.color = color;
        img.raycastTarget = false;
    }

    static GameObject CreateHorizontalGroup(Transform parent, string name,
        Vector2 anchorMin, Vector2 anchorMax,
        Vector2 offsetMin, Vector2 offsetMax,
        float spacing, bool childAlign = true, bool useCG = true, bool packAtEnd = false)
    {
        var go = new GameObject(name);
        go.transform.SetParent(parent, false);
        var rect = go.AddComponent<RectTransform>();
        rect.anchorMin = anchorMin;
        rect.anchorMax = anchorMax;
        rect.offsetMin = offsetMin;
        rect.offsetMax = offsetMax;

        var layout = go.AddComponent<HorizontalLayoutGroup>();
        layout.spacing = spacing;
        layout.childAlignment = packAtEnd ? TextAnchor.LowerRight : TextAnchor.MiddleLeft;
        layout.childControlWidth = useCG;
        layout.childControlHeight = useCG;
        layout.childForceExpandWidth = childAlign;
        layout.childForceExpandHeight = childAlign;
        layout.padding = new RectOffset(8, 8, 4, 4);

        if (useCG)
        {
            var fitter = go.AddComponent<ContentSizeFitter>();
            fitter.horizontalFit = ContentSizeFitter.FitMode.PreferredSize;
            fitter.verticalFit = ContentSizeFitter.FitMode.PreferredSize;
        }
        return go;
    }

    static GameObject CreateIcon(Transform parent, string name, string spritePath,
        Vector2 anchorMin, Vector2 anchorMax,
        Vector2 offsetMin, Vector2 offsetMax,
        Vector2 size)
    {
        var go = new GameObject(name);
        go.transform.SetParent(parent, false);
        var rect = go.AddComponent<RectTransform>();
        rect.anchorMin = anchorMin;
        rect.anchorMax = anchorMax;
        rect.sizeDelta = size;
        rect.anchoredPosition = offsetMin;

        var img = go.AddComponent<Image>();
        img.raycastTarget = false;

        // Try loading sprite
        var sprite = UnityEditor.AssetDatabase.LoadAssetAtPath<Sprite>(spritePath);
        if (sprite != null)
        {
            img.sprite = sprite;
            img.preserveAspect = true;
        }
        else
        {
            img.color = COL_GOLD; // Fallback color
        }
        return go;
    }

    static GameObject CreateLabel(Transform parent, string name, string text,
        int fontSize, FontStyle fontStyle, Color color, TextAnchor alignment,
        Vector2 anchorMin, Vector2 anchorMax,
        Vector2 offsetMin, Vector2 offsetMax)
    {
        var go = new GameObject(name);
        go.transform.SetParent(parent, false);
        var rect = go.AddComponent<RectTransform>();
        rect.anchorMin = anchorMin;
        rect.anchorMax = anchorMax;
        rect.offsetMin = offsetMin;
        rect.offsetMax = offsetMax;

        var uiText = go.AddComponent<Text>();
        uiText.text = text;
        uiText.fontSize = fontSize;
        uiText.fontStyle = fontStyle;
        uiText.color = color;
        uiText.alignment = alignment;
        if (_font != null) uiText.font = _font;
        uiText.raycastTarget = false;
        uiText.horizontalOverflow = HorizontalWrapMode.Overflow;
        return go;
    }

    static void AddOutline(GameObject textObj, Color effectColor, Vector2 distance)
    {
        var outline = textObj.AddComponent<Outline>();
        outline.effectColor = effectColor;
        outline.effectDistance = distance;
    }

