using UnityEngine;
using UnityEngine.UI;

// ============================================
// 精美奇幻风塔防游戏 HUD 界面构建脚本
// ============================================

public static class HUDBuilder
{
    // 颜色方案 - 中世纪奇幻风
    static readonly Color COL_BG_DARK = new Color(0.16f, 0.12f, 0.08f, 0.92f);
    static readonly Color COL_GOLD = new Color(0.83f, 0.65f, 0.2f, 1f);
    static readonly Color COL_GOLD_DARK = new Color(0.6f, 0.45f, 0.1f, 1f);
    static readonly Color COL_CREAM = new Color(1f, 0.95f, 0.8f, 1f);
    static readonly Color COL_RED = new Color(0.85f, 0.2f, 0.15f, 1f);
    static readonly Color COL_BLUE = new Color(0.3f, 0.55f, 0.9f, 1f);
    static readonly Color COL_GREEN = new Color(0.2f, 0.75f, 0.3f, 1f);
    static readonly Color COL_PANEL_BG = new Color(0.12f, 0.08f, 0.05f, 0.95f);
    static readonly Color COL_OVERLAY = new Color(0f, 0f, 0f, 0.7f);
    static readonly Color COL_STAMINA = new Color(0.2f, 0.8f, 0.4f, 1f);

    static Sprite LoadSprite(string path)
    {
        var obj = Resources.Load<Sprite>(path);
        if (obj != null) return obj;
        // Try loading as Texture2D and convert
        return null;
    }

    static Sprite LoadSpriteFromAsset(string assetPath)
    {
        // Load from Assets/ path
        var sprite = UnityEditor.AssetDatabase.LoadAssetAtPath<Sprite>(assetPath);
        if (sprite != null) return sprite;
        // Try loading texture
        var tex = UnityEditor.AssetDatabase.LoadAssetAtPath<Texture2D>(assetPath);
        if (tex != null)
        {
            Debug.Log($"[HUD] Loaded texture from: {assetPath}");
        }
        else
        {
            Debug.LogWarning($"[HUD] Could not load: {assetPath}");
        }
        return sprite;
    }

    static Texture2D LoadTexture(string assetPath)
    {
        return UnityEditor.AssetDatabase.LoadAssetAtPath<Texture2D>(assetPath);
    }

    static AudioClip LoadAudioClip(string assetPath)
    {
        return UnityEditor.AssetDatabase.LoadAssetAtPath<AudioClip>(assetPath);
    }

    public static void Build()
    {
        // === 1. CREATE CANVAS ===
        var canvasObj = new GameObject("HUD_Canvas");
        var canvas = canvasObj.AddComponent<Canvas>();
        canvas.renderMode = RenderMode.ScreenSpaceOverlay;
        canvas.sortingOrder = 100;

        var scaler = canvasObj.AddComponent<CanvasScaler>();
        scaler.uiScaleMode = CanvasScaler.ScaleMode.ScaleWithScreenSize;
        scaler.referenceResolution = new Vector2(1920, 1080);
        scaler.matchWidthOrHeight = 0.5f;

        canvasObj.AddComponent<GraphicRaycaster>();

        // Load assets
        var iconGold = LoadSpriteFromAsset("Assets/Art/UI/Icons/icon_gold.png");
        var iconDiamond = LoadSpriteFromAsset("Assets/Art/UI/Icons/icon_diamond 2.png");
        var iconHeart = LoadSpriteFromAsset("Assets/Art/UI/Icons/icon_heart 1.png");
        var iconWave = LoadSpriteFromAsset("Assets/Art/UI/Icons/icon_wave 1.png");
