    // === HELPER METHODS ===

    static GameObject CreateUIElement(string name, Transform parent)
    {
        var obj = new GameObject(name);
        obj.transform.SetParent(parent, false);
        var rect = obj.AddComponent<RectTransform>();
        return obj;
    }

    static void SetStretch(GameObject obj, Vector2 anchorMin, Vector2 anchorMax, Vector2 offsetMin, Vector2 offsetMax)
    {
        var rect = obj.GetComponent<RectTransform>();
        rect.anchorMin = anchorMin;
        rect.anchorMax = anchorMax;
        rect.offsetMin = offsetMin;
        rect.offsetMax = offsetMax;
    }

    static GameObject CreateHorizontalGroup(string name, Transform parent, Vector2 anchoredPos, Vector2 size, Vector2 anchorMin, Vector2 pivot, int spacing, TextAnchor alignment)
    {
        var obj = CreateUIElement(name, parent);
        var rect = obj.GetComponent<RectTransform>();
        rect.anchorMin = anchorMin;
        rect.anchorMax = anchorMin;
        rect.pivot = pivot;
        rect.anchoredPosition = anchoredPos;
        rect.sizeDelta = size;
        var layout = obj.AddComponent<HorizontalLayoutGroup>();
        layout.spacing = spacing;
        layout.childAlignment = alignment;
        layout.childControlWidth = false;
        layout.childControlHeight = false;
        layout.childForceExpandWidth = false;
        layout.childForceExpandHeight = false;
        layout.padding = new RectOffset(5, 5, 5, 5);
        return obj;
    }

    static GameObject CreateIcon(string name, Transform parent, Sprite sprite, Vector2 size)
    {
        var obj = CreateUIElement(name, parent);
        var rect = obj.GetComponent<RectTransform>();
        rect.sizeDelta = size;
        var img = obj.AddComponent<Image>();
        img.sprite = sprite;
        img.preserveAspect = true;
        var layout = obj.AddComponent<LayoutElement>();
        layout.preferredWidth = size.x;
        layout.preferredHeight = size.y;
        return obj;
    }

    static GameObject CreateColoredIcon(string name, Transform parent, Color color, Vector2 size)
    {
        var obj = CreateUIElement(name, parent);
        var rect = obj.GetComponent<RectTransform>();
        rect.sizeDelta = size;
        var img = obj.AddComponent<Image>();
        img.color = color;
        var layout = obj.AddComponent<LayoutElement>();
        layout.preferredWidth = size.x;
        layout.preferredHeight = size.y;
        return obj;
    }

    static GameObject CreateText(string name, Transform parent, string text, int fontSize, Color color, FontStyle fontStyle, TextAnchor alignment)
    {
        var obj = CreateUIElement(name, parent);
        var txt = obj.AddComponent<Text>();
        txt.text = text;
        txt.fontSize = fontSize;
        txt.color = color;
        txt.fontStyle = fontStyle;
        txt.alignment = alignment;
        txt.font = Resources.GetBuiltinResource<Font>("Arial.ttf");
