    hlg.spacing = 8; hlg.childControlWidth = false; hlg.childControlHeight = false;
    hlg.childForceExpandWidth = false; hlg.childForceExpandHeight = false;
    hlg.padding = new RectOffset(5,5,5,5);
    // Icon
    var ico = new GameObject("Icon");
    ico.transform.SetParent(g.transform, false);
    var ir = ico.AddComponent<RectTransform>(); ir.sizeDelta = new Vector2(40,40);
    var icoImg = ico.AddComponent<Image>(); icoImg.color = iconColor;
    var icoLE = ico.AddComponent<LayoutElement>(); icoLE.preferredWidth=40; icoLE.preferredHeight=40;
    // Text
    var txt = new GameObject("Text");
    txt.transform.SetParent(g.transform, false);
    var tr = txt.AddComponent<RectTransform>(); tr.sizeDelta = new Vector2(groupW-60, 45);
    var t = txt.AddComponent<Text>();
    t.text = value; t.fontSize = 26; t.color = valColor; t.fontStyle = FontStyle.Bold;
    t.alignment = TextAnchor.MiddleLeft; t.font = Resources.GetBuiltinResource<Font>("Arial.ttf");
    t.horizontalOverflow = HorizontalWrapMode.Overflow;
    var ole = txt.AddComponent<Outline>(); ole.effectColor = new Color(0,0,0,0.7f); ole.effectDistance = new Vector2(2,-2);
    var tle = txt.AddComponent<LayoutElement>(); tle.preferredWidth = groupW-60;
}

