sT.color = Color.white; sT.alignment = TextAnchor.MiddleCenter;
sT.font = Resources.GetBuiltinResource<Font>("Arial.ttf");
var str = sTxt.GetComponent<RectTransform>(); str.anchorMin=Vector2.zero; str.anchorMax=Vector2.one;
str.offsetMin=Vector2.zero; str.offsetMax=Vector2.zero;

Debug.Log("[HUD] Part 1 done: Canvas + TopBar + Controls");

