using UnityEngine;
using UnityEngine.UI;
using UnityEditor;
using UnityEditor.SceneManagement;

public static class HUDBuilder
{
    [MenuItem("Tools/Build Fantasy HUD")]
    public static void Build()
    {
        var canvas = GameObject.Find("HUD_Canvas");
        if (canvas == null) { Debug.LogError("HUD_Canvas not found!"); return; }

        var COL_BG = new Color(0.16f, 0.12f, 0.08f, 0.92f);
        var COL_GOLD = new Color(0.83f, 0.65f, 0.2f, 1f);
        var COL_GOLD_DK = new Color(0.6f, 0.45f, 0.1f, 1f);
        var COL_CREAM = new Color(1f, 0.95f, 0.8f, 1f);
        var COL_RED = new Color(0.85f, 0.2f, 0.15f, 1f);
        var COL_BLUE = new Color(0.3f, 0.55f, 0.9f, 1f);
        var COL_GREEN = new Color(0.2f, 0.75f, 0.3f, 1f);
        var COL_PANEL = new Color(0.12f, 0.08f, 0.05f, 0.95f);
        var COL_OVERLAY = new Color(0f, 0f, 0f, 0.7f);
        var COL_STAMINA = new Color(0.2f, 0.8f, 0.4f, 1f);
        var font = Resources.GetBuiltinResource<Font>("Arial.ttf");

        // === TOP BAR ===
        var topBar = CreateObj("TopBar", canvas.transform);
        SetAnchors(topBar, new Vector2(0,1), new Vector2(1,1), new Vector2(0,-80), new Vector2(0,-10));
        topBar.AddComponent<Image>().color = COL_BG;
        // Border
        var bdr = CreateObj("Border", topBar.transform);
        SetAnchors(bdr, Vector2.zero, Vector2.one, Vector2.zero, new Vector2(0,-3));
        bdr.AddComponent<Image>().color = COL_GOLD_DK;
        // Stat groups
        MakeStat("GoldGroup", topBar.transform, 20, COL_GOLD, "1,234", COL_GOLD, 280, font);
        MakeStat("DiamondGroup", topBar.transform, 310, COL_BLUE, "56", COL_BLUE, 220, font);
        MakeStat("LifeGroup", topBar.transform, 540, COL_RED, "20", COL_RED, 180, font);
        MakeStat("WaveGroup", topBar.transform, 730, Color.gray, "Wave 3/10", COL_CREAM, 250, font);
        MakeStat("StaminaGroup", topBar.transform, 990, COL_STAMINA, "50/100", COL_STAMINA, 180, font);
        // Control buttons
        var ctrl = CreateObj("ControlGroup", topBar.transform);
        var cr = ctrl.GetComponent<RectTransform>();
        cr.anchorMin = cr.anchorMax = new Vector2(1,1); cr.pivot = new Vector2(1,1);
        cr.anchoredPosition = new Vector2(-15,-10); cr.sizeDelta = new Vector2(200,55);
        var chlg = ctrl.AddComponent<HorizontalLayoutGroup>();
        chlg.spacing=12; chlg.childControlWidth=false; chlg.childControlHeight=false;
        chlg.childForceExpandWidth=false; chlg.childForceExpandHeight=false; chlg.childAlignment=TextAnchor.MiddleRight;
        MakeBtn("PauseBtn", ctrl.transform, "||", COL_GOLD_DK, 55, 55, font);
        MakeBtn("SpeedBtn", ctrl.transform, "1x", COL_GOLD_DK, 85, 55, font);

        // === WAVE START BUTTON ===
        var wsb = CreateObj("WaveStartBtn", canvas.transform);
        var wr = wsb.GetComponent<RectTransform>();
        wr.anchorMin = wr.anchorMax = new Vector2(0.5f,0.5f); wr.pivot = new Vector2(0.5f,0.5f);
        wr.anchoredPosition = new Vector2(0,100); wr.sizeDelta = new Vector2(300,80);
        wsb.AddComponent<Image>().color = COL_RED;
        var wBtn = wsb.AddComponent<Button>();
        var wc = wBtn.colors; wc.highlightedColor=new Color(1f,0.3f,0.2f); wc.pressedColor=new Color(0.7f,0.15f,0.1f); wBtn.colors=wc;
        var wt = MakeText("Label", wsb.transform, "START WAVE", 32, Color.white, FontStyle.Bold, font);
        SetStretchFill(wt.GetComponent<RectTransform>());

        // === TOWER SELECT PANEL ===
        var tp = CreateObj("TowerSelectPanel", canvas.transform);
        var tpr = tp.GetComponent<RectTransform>();
        tpr.anchorMin = new Vector2(0,0); tpr.anchorMax = new Vector2(1,0); tpr.pivot = new Vector2(0.5f,0);
        tpr.offsetMin = new Vector2(0,0); tpr.offsetMax = new Vector2(0,160);
        tp.AddComponent<Image>().color = COL_BG;
        var tpb = CreateObj("Border", tp.transform);
        SetAnchors(tpb, new Vector2(0,1), new Vector2(1,1), new Vector2(0,-3), new Vector2(0,0));
        tpb.AddComponent<Image>().color = COL_GOLD_DK;
        var tt = MakeText("Title", tp.transform, "BUILD TOWERS", 22, COL_GOLD, FontStyle.Bold, font);
        var ttr = tt.GetComponent<RectTransform>();
        ttr.anchorMin=new Vector2(0,1); ttr.anchorMax=new Vector2(1,1); ttr.pivot=new Vector2(0.5f,1);
        ttr.anchoredPosition=new Vector2(0,-10); ttr.sizeDelta=new Vector2(400,35);
        // Tower container
        var tc = CreateObj("TowerContainer", tp.transform);
        var tcr = tc.GetComponent<RectTransform>();
        tcr.anchorMin=Vector2.zero; tcr.anchorMax=new Vector2(1,1);
        tcr.offsetMin=new Vector2(20,10); tcr.offsetMax=new Vector2(-20,-45);
        var tclg = tc.AddComponent<HorizontalLayoutGroup>();
        tclg.spacing=15; tclg.childControlWidth=false; tclg.childControlHeight=false;
        tclg.childForceExpandWidth=false; tclg.childForceExpandHeight=false; tclg.childAlignment=TextAnchor.MiddleCenter;
        // Tower buttons
        string[] tNames = {"Archer","Barracks","Mage","Cannon"};
        Color[] tColors = {COL_GREEN, new Color(0.8f,0.5f,0.2f), new Color(0.5f,0.2f,0.8f), new Color(0.7f,0.3f,0.3f)};
        string[] tCosts = {"100G","120G","150G","200G"};
        for(int i=0;i<4;i++) MakeTowerBtn("Tower_"+i, tc.transform, tNames[i], tCosts[i], tColors[i], font);

        // === VICTORY PANEL ===
        var vp = CreateObj("VictoryPanel", canvas.transform);
        SetAnchors(vp, Vector2.zero, Vector2.one, Vector2.zero, Vector2.zero);
        vp.AddComponent<Image>().color = COL_OVERLAY;
        vp.SetActive(false);
        var vc = CreateObj("Content", vp.transform);
        var vcr = vc.GetComponent<RectTransform>();
        vcr.anchorMin=vcr.anchorMax=new Vector2(0.5f,0.5f); vcr.pivot=new Vector2(0.5f,0.5f);
        vcr.sizeDelta=new Vector2(600,500);
        vc.AddComponent<Image>().color = COL_PANEL;
        var vcb = CreateObj("Border", vc.transform);
        SetAnchors(vcb, Vector2.zero, Vector2.one, new Vector2(3,3), new Vector2(-3,-3));
        vcb.AddComponent<Image>().color = COL_GOLD;
        var vlg = vc.AddComponent<VerticalLayoutGroup>();
        vlg.spacing=15; vlg.padding=new RectOffset(30,30,40,30); vlg.childAlignment=TextAnchor.MiddleCenter;
        vlg.childControlWidth=true; vlg.childForceExpandHeight=false;
        var vt1 = MakeText("Title", vc.transform, "VICTORY!", 42, COL_GOLD, FontStyle.Bold, font);
        vt1.AddComponent<LayoutElement>().preferredHeight=60;
        // Stars
        var sr = CreateObj("Stars", vc.transform);
        var srlg = sr.AddComponent<HorizontalLayoutGroup>();
        srlg.spacing=20; srlg.childControlWidth=false; srlg.childControlHeight=false;
        srlg.childForceExpandWidth=false; srlg.childForceExpandHeight=false; srlg.childAlignment=TextAnchor.MiddleCenter;
        sr.AddComponent<LayoutElement>().preferredHeight=70;
        for(int i=0;i<3;i++){var s=MakeText("S"+i,sr.transform,"★",50,i<2?COL_GOLD:new Color(0.3f,0.3f,0.3f),FontStyle.Normal,font);s.AddComponent<LayoutElement>().preferredWidth=60;}
        MakeText("K",vc.transform,"Enemies Slain: 47",24,COL_CREAM,FontStyle.Normal,font).AddComponent<LayoutElement>().preferredHeight=35;
        MakeText("G",vc.transform,"Gold Earned: 1,250",24,COL_GOLD,FontStyle.Normal,font).AddComponent<LayoutElement>().preferredHeight=35;
        MakeText("W",vc.transform,"Waves Cleared: 10/10",24,COL_CREAM,FontStyle.Normal,font).AddComponent<LayoutElement>().preferredHeight=35;
        // Victory buttons
        var vbr = CreateObj("BtnRow", vc.transform);
        var vbrlg = vbr.AddComponent<HorizontalLayoutGroup>();
        vbrlg.spacing=20; vbrlg.childControlWidth=false; vbrlg.childControlHeight=false;
        vbrlg.childForceExpandWidth=false; vbrlg.childForceExpandHeight=false; vbrlg.childAlignment=TextAnchor.MiddleCenter;
        vbr.AddComponent<LayoutElement>().preferredHeight=55;
        MakeMenuBtn("Restart",vbr.transform,"RESTART",COL_RED,160,50,font);
        MakeMenuBtn("Next",vbr.transform,"NEXT",COL_GREEN,160,50,font);
        MakeMenuBtn("Menu",vbr.transform,"MENU",COL_GOLD_DK,160,50,font);

        // === PAUSE MENU ===
        var pm = CreateObj("PauseMenu", canvas.transform);
        SetAnchors(pm, Vector2.zero, Vector2.one, Vector2.zero, Vector2.zero);
        pm.AddComponent<Image>().color = COL_OVERLAY;
        pm.SetActive(false);
        var pc = CreateObj("Content", pm.transform);
        var pcr = pc.GetComponent<RectTransform>();
        pcr.anchorMin=pcr.anchorMax=new Vector2(0.5f,0.5f); pcr.pivot=new Vector2(0.5f,0.5f);
        pcr.sizeDelta=new Vector2(400,350);
        pc.AddComponent<Image>().color = COL_PANEL;
        var pcb = CreateObj("Border", pc.transform);
        SetAnchors(pcb, Vector2.zero, Vector2.one, new Vector2(3,3), new Vector2(-3,-3));
        pcb.AddComponent<Image>().color = COL_GOLD;
        var plg = pc.AddComponent<VerticalLayoutGroup>();
        plg.spacing=20; plg.padding=new RectOffset(30,30,40,30); plg.childAlignment=TextAnchor.MiddleCenter;
        plg.childControlWidth=true; plg.childForceExpandHeight=false;
        MakeText("Title",pc.transform,"PAUSED",38,COL_GOLD,FontStyle.Bold,font).AddComponent<LayoutElement>().preferredHeight=55;
        MakeText("VL",pc.transform,"Volume",22,COL_CREAM,FontStyle.Normal,font).AddComponent<LayoutElement>().preferredHeight=30;
        var sl = CreateObj("Slider",pc.transform);
        sl.AddComponent<LayoutElement>().preferredHeight=35;
        sl.AddComponent<Slider>().value=0.8f;
        MakeMenuBtn("Resume",pc.transform,"RESUME",COL_GREEN,0,50,font);
        MakeMenuBtn("Restart",pc.transform,"RESTART",COL_RED,0,50,font);
        MakeMenuBtn("Quit",pc.transform,"QUIT TO MENU",COL_GOLD_DK,0,50,font);

        EditorSceneManager.MarkSceneDirty(EditorSceneManager.GetActiveScene());
        Debug.Log("[HUD] Fantasy HUD built successfully!");
    }

    static GameObject CreateObj(string name, Transform parent)
    {
        var obj = new GameObject(name);
        obj.transform.SetParent(parent, false);
        obj.AddComponent<RectTransform>();
        return obj;
    }
    static void SetAnchors(GameObject obj, Vector2 aMin, Vector2 aMax, Vector2 oMin, Vector2 oMax)
    {
        var r = obj.GetComponent<RectTransform>();
        r.anchorMin=aMin; r.anchorMax=aMax; r.offsetMin=oMin; r.offsetMax=oMax;
    }
    static void SetStretchFill(RectTransform r)
    {
        r.anchorMin=Vector2.zero; r.anchorMax=Vector2.one; r.offsetMin=Vector2.zero; r.offsetMax=Vector2.zero;
    }
    static void MakeStat(string name, Transform parent, float x, Color iconColor, string value, Color valColor, float w, Font font)
    {
        var g = CreateObj(name, parent);
        var r = g.GetComponent<RectTransform>();
        r.anchorMin=r.anchorMax=new Vector2(0,1); r.pivot=new Vector2(0,0.5f);
        r.anchoredPosition=new Vector2(x,-45); r.sizeDelta=new Vector2(w,55);
        var hlg = g.AddComponent<HorizontalLayoutGroup>();
        hlg.spacing=8; hlg.childControlWidth=false; hlg.childControlHeight=false;
        hlg.childForceExpandWidth=false; hlg.childForceExpandHeight=false;
        hlg.padding=new RectOffset(5,5,5,5);
        var ico = CreateObj("Icon", g.transform);
        ico.GetComponent<RectTransform>().sizeDelta=new Vector2(40,40);
        ico.AddComponent<Image>().color=iconColor;
        var ile = ico.AddComponent<LayoutElement>(); ile.preferredWidth=40; ile.preferredHeight=40;
        var txt = MakeText("Text", g.transform, value, 26, valColor, FontStyle.Bold, font);
        var tle = txt.AddComponent<LayoutElement>(); tle.preferredWidth=w-60;
    }
    static GameObject MakeText(string name, Transform parent, string text, int size, Color color, FontStyle style, Font font)
    {
        var obj = CreateObj(name, parent);
        var t = obj.AddComponent<Text>();
        t.text=text; t.fontSize=size; t.color=color; t.fontStyle=style;
        t.alignment=TextAnchor.MiddleCenter; t.font=font;
        t.horizontalOverflow=HorizontalWrapMode.Overflow; t.verticalOverflow=VerticalWrapMode.Overflow;
        var ol = obj.AddComponent<Outline>(); ol.effectColor=new Color(0,0,0,0.7f); ol.effectDistance=new Vector2(2,-2);
        return obj;
    }
    static void MakeBtn(string name, Transform parent, string label, Color bg, float w, float h, Font font)
    {
        var obj = CreateObj(name, parent);
        obj.GetComponent<RectTransform>().sizeDelta=new Vector2(w,h);
        obj.AddComponent<Image>().color=bg;
        var btn = obj.AddComponent<Button>();
        var c = btn.colors; c.highlightedColor=new Color(0.83f,0.65f,0.2f); btn.colors=c;
        var le = obj.AddComponent<LayoutElement>(); le.preferredWidth=w; le.preferredHeight=h;
        var t = MakeText("L", obj.transform, label, 20, Color.white, FontStyle.Bold, font);
        SetStretchFill(t.GetComponent<RectTransform>());
    }
    static void MakeTowerBtn(string name, Transform parent, string tName, string cost, Color accent, Font font)
    {
        var obj = CreateObj(name, parent);
        obj.GetComponent<RectTransform>().sizeDelta=new Vector2(180,110);
        var le = obj.AddComponent<LayoutElement>(); le.preferredWidth=180; le.preferredHeight=110;
        obj.AddComponent<Image>().color=new Color(0.15f,0.1f,0.06f,0.95f);
        var bdr = CreateObj("Border", obj.transform);
        SetAnchors(bdr, Vector2.zero, Vector2.one, new Vector2(2,2), new Vector2(-2,-2));
        bdr.AddComponent<Image>().color=accent;
        var ta = CreateObj("Accent", obj.transform);
        var tar = ta.GetComponent<RectTransform>();
        tar.anchorMin=new Vector2(0,1); tar.anchorMax=new Vector2(1,1); tar.pivot=new Vector2(0.5f,1);
        tar.sizeDelta=new Vector2(0,5); ta.AddComponent<Image>().color=accent;
        var nt = MakeText("N",obj.transform,tName,18,new Color(1f,0.95f,0.8f),FontStyle.Bold,font);
        var ntr = nt.GetComponent<RectTransform>();
        ntr.anchorMin=new Vector2(0,0.4f); ntr.anchorMax=new Vector2(1,1);
        ntr.offsetMin=new Vector2(5,0); ntr.offsetMax=new Vector2(-5,-5);
        var ct = MakeText("C",obj.transform,cost,20,new Color(0.83f,0.65f,0.2f),FontStyle.Bold,font);
        var ctr = ct.GetComponent<RectTransform>();
        ctr.anchorMin=Vector2.zero; ctr.anchorMax=new Vector2(1,0.4f);
        ctr.offsetMin=new Vector2(5,5); ctr.offsetMax=new Vector2(-5,0);
        var btn = obj.AddComponent<Button>();
        var bc = btn.colors;
        bc.highlightedColor=new Color(accent.r*1.3f,accent.g*1.3f,accent.b*1.3f);
        bc.pressedColor=new Color(0.1f,0.08f,0.05f); btn.colors=bc;
    }
    static void MakeMenuBtn(string name, Transform parent, string label, Color color, float w, float h, Font font)
    {
        var obj = CreateObj(name, parent);
        obj.AddComponent<Image>().color=color;
        var btn = obj.AddComponent<Button>();
        var c = btn.colors;
        c.highlightedColor=new Color(color.r*1.3f,color.g*1.3f,color.b*1.3f);
        c.pressedColor=new Color(color.r*0.6f,color.g*0.6f,color.b*0.6f); btn.colors=c;
        var le = obj.AddComponent<LayoutElement>(); le.preferredHeight=h; if(w>0) le.preferredWidth=w;
        var t = MakeText("L", obj.transform, label, 22, Color.white, FontStyle.Bold, font);
        SetStretchFill(t.GetComponent<RectTransform>());
    }
}

