args.script:
// Apply AI-generated sprites to HUD icons
var iconPaths = new System.Collections.Generic.Dictionary<string, string>() {
    {"GoldGroup/Icon", "Assets/Art/UI/Icons/icon_gold.png"},
    {"DiamondGroup/Icon", "Assets/Art/UI/Icons/icon_diamond 2.png"},
    {"LifeGroup/Icon", "Assets/Art/UI/Icons/icon_heart 1.png"},
    {"WaveGroup/Icon", "Assets/Art/UI/Icons/icon_wave 1.png"}
};
var canvas = GameObject.Find("HUD_Canvas");
if (canvas == null) { Debug.LogError("HUD_Canvas not found"); return; }
int applied = 0;
foreach (var kvp in iconPaths) {
    var t = canvas.transform.Find("TopBar/" + kvp.Key);
    if (t != null) {
        var img = t.GetComponent<UnityEngine.UI.Image>();
        if (img != null) {
            var sprite = UnityEditor.AssetDatabase.LoadAssetAtPath<Sprite>(kvp.Value);
            if (sprite != null) { img.sprite = sprite; img.preserveAspect = true; applied++; }
            else Debug.LogWarning($"Sprite not found: {kvp.Value}");
        }
    } else Debug.LogWarning($"Transform not found: TopBar/{kvp.Key}");
}
Debug.Log($"[HUD] Applied {applied} AI-generated sprites to HUD icons");

